const { loadConfig } = require('../src/config');
const { renderTemplateToPng } = require('../src/render-template');

async function main() {
  const config = loadConfig();

  const outputPath = await renderTemplateToPng(config, {
    headline: 'Render Test',
    lines: [
      'Header / Content / Footer zones are now template-driven.',
      'This PNG is generated by Playwright.',
      'Next step is printing this PNG over socket.'
    ],
    printedAt: new Date().toLocaleString()
  });

  console.log(JSON.stringify({ ok: true, test: 'render', outputPath }, null, 2));
}

main().catch((error) => {
  console.error(JSON.stringify({ ok: false, test: 'render', error: error.message }, null, 2));
  process.exit(1);
});
